// ... (компонент HomePage остается без изменений) ...
interface HomePageProps {
  allProducts: Product[];
  error?: string;
}

export default function HomePage({ allProducts, error }: HomePageProps) {
  // ... ваш JSX ...
}

export const getServerSideProps: GetServerSideProps = async () => {
  // --- ИСПРАВЛЕНИЕ: Вызываем функцию для получения dbAdmin ---
  const dbAdmin = getAdminDb();

  if (!dbAdmin) {
    return {
      props: {
        allProducts: [],
        error: "Firebase Admin SDK initialization failed on server. Check server logs.",
      },
    };
  }

  try {
    console.log("Fetching products with Admin SDK...");
    const productsSnapshot = await dbAdmin.collection('products').get();
    const allProducts = productsSnapshot.docs.map(doc => doc.data() as Product);
    console.log(`Successfully fetched ${allProducts.length} products.`);

    return {
      props: {
        allProducts: JSON.parse(JSON.stringify(allProducts)), // Сериализация все еще нужна
      },
    };
  } catch (error) {
    console.error("Error fetching data in getServerSideProps:", error);
    return {
      props: {
        allProducts: [],
        error: error.message,
      },
    };
  }
};
